type OperationalMetric = { count: number; totalMs: number; maxMs: number; errors: number };
const moduleAccessCache = new Map<string, { enabled: boolean; checkedAt: number }>();
const MODULE_CACHE_MS = 30_000;

function routeBucket(req: express.Request) {
  const pathName = req.path || "";
  if (pathName === "/api/auth/login") return { name: "auth", limit: 12, windowMs: 60_000 };
  if (pathName.includes("/exports")) return { name: "exports", limit: 30, windowMs: 60_000 };
  if (pathName.includes("/upload") || pathName.startsWith("/uploads")) return { name: "uploads", limit: 40, windowMs: 60_000 };
  if (/(approve|reject|action|calculate|recalculate|read-all|test)/i.test(pathName)) return { name: "sensitive-actions", limit: 80, windowMs: 60_000 };
  return null;
}

function safeLog(details: Record<string, unknown>) {
  console.log(JSON.stringify({ service: "zenjo-api", ...details }));
}

const runtimeStore = createRuntimeStore(environmentReport.adapter, process.env["REDIS_URL"], safeLog);

safeLog({
  event: environmentReport.ok ? "environment_validation_passed" : "environment_validation_warning",
  environment: environmentReport.environment,
  adapter: environmentReport.adapter,
  issueCount: environmentReport.issues.length,
  issues: environmentReport.issues,
});

function metricKey(req: express.Request) {
  const route = (req.route?.path && typeof req.route.path === "string") ? req.route.path : req.path;
  return `${req.method} ${route}`;
}

app.use((req, res, next) => {
  const requestId = String(req.headers["x-request-id"] || crypto.randomUUID());
  (req as any).requestId = requestId;
  res.setHeader("x-request-id", requestId);
  const started = Date.now();
  res.on("finish", () => {
    const durationMs = Date.now() - started;
    const user = (req as Partial<AuthReq>).user;
    const key = metricKey(req);
    void runtimeStore.recordMetric(key, durationMs, res.statusCode >= 500).catch((error) => {
      safeLog({ level: "error", event: "metric_record_failed", error: (error as Error).message });
    });
    safeLog({
      level: res.statusCode >= 500 ? "error" : "info",
      event: "http_request",
      requestId,
      method: req.method,
      route: req.route?.path || req.path,
      status: res.statusCode,
      durationMs,
      userId: user?.userId ?? null,
      companyId: user?.companyId ?? null,
      role: user?.role ?? null,
    });
  });
  next();
});

app.use(async (req, res, next) => {
  if (["/api/healthz", "/api/readiness", "/api/version"].includes(req.path)) return next();
  const bucket = routeBucket(req);
  if (!bucket) return next();
  const key = `${bucket.name}:${req.ip}:${(req as Partial<AuthReq>).user?.userId ?? "anon"}`;
  const entry = await runtimeStore.rateLimit(key, bucket.limit, bucket.windowMs);
  res.setHeader("x-rate-limit-limit", String(bucket.limit));
  res.setHeader("x-rate-limit-remaining", String(entry.remaining));
  res.setHeader("retry-after", String(Math.ceil(Math.max(0, entry.resetAt - Date.now()) / 1000)));
  if (!entry.allowed) {
    res.status(429).json({ success: false, message: "Too many requests. Please retry shortly.", requestId: (req as any).requestId });
    return;
  }
  next();
});

app.use(async (req, res, next) => {
  const moduleKey = moduleForApiPath(req.path || "");
  if (!moduleKey || req.path === "/api/tenant/modules/status") return next();
  const authHeader = req.headers.authorization || "";
  if (!authHeader.startsWith("Bearer ")) return next();
  const payload = verifyToken(authHeader.slice(7));
  if (!payload) return next();
  const companyId = Number(payload["companyId"]);
  if (!companyId) return next();
  const cacheKey = `${companyId}:${moduleKey}`;
  const cached = moduleAccessCache.get(cacheKey);
  if (cached && Date.now() - cached.checkedAt < MODULE_CACHE_MS) {
    if (!cached.enabled) {
      res.status(403).json({ success: false, message: "Module is disabled for this tenant", module: moduleKey });
      return;
    }
    return next();
  }
  try {
    const { rows } = await pool.query(`SELECT is_enabled FROM company_modules WHERE company_id = $1 AND module_key = $2 LIMIT 1`, [companyId, moduleKey]);
    const enabled = rows.length === 0 ? true : rows[0].is_enabled !== false;
    moduleAccessCache.set(cacheKey, { enabled, checkedAt: Date.now() });
    if (!enabled) {
      res.status(403).json({ success: false, message: "Module is disabled for this tenant", module: moduleKey });
      return;
    }
  } catch (error) {
    safeLog({ event: "module_access_check_failed", module: moduleKey, companyId, error: (error as Error).message });
  }
  next();
});

// â”€â”€â”€ File upload (multer) â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
const UPLOADS_DIR = environmentReport.paths.uploadsDir;
if (!fs.existsSync(UPLOADS_DIR)) fs.mkdirSync(UPLOADS_DIR, { recursive: true });
const storageAdapter = createStorageAdapter(process.env, UPLOADS_DIR);

const docStorage = multer.diskStorage({
  destination: (_req, _file, cb) => cb(null, UPLOADS_DIR),
  filename: (_req, file, cb) => {
    const ext = path.extname(file.originalname).toLowerCase();
    cb(null, `doc_${Date.now()}_${Math.random().toString(36).slice(2)}${ext}`);
  },
});
const ALLOWED_DOC_MIMES = new Set(["application/pdf", "image/jpeg", "image/jpg", "image/png", "image/webp"]);
const docUpload = multer({
  storage: docStorage,
  limits: { fileSize: 5 * 1024 * 1024 },
  fileFilter: (_req, file, cb) => {
    const ext = path.extname(file.originalname || "").toLowerCase();
    const allowedExts = new Set([".pdf", ".jpg", ".jpeg", ".png", ".webp"]);
    if (ALLOWED_DOC_MIMES.has(file.mimetype) && allowedExts.has(ext)) cb(null, true);
    else cb(new Error("Unsupported file type. Allowed: PDF, JPEG, PNG, WEBP"));
  },
});

