      titleEn: "New Leave Request",
      messageAr: `ظ‚ط¯ظ‘ظ… ${empName} ط·ظ„ط¨ ط¥ط¬ط§ط²ط© ظ…ظ† ${dateRange}.`,
      messageEn: `${empName} submitted a leave request from ${dateRange}.`,
