const JORDAN_HOLIDAYS = [
  { id: 1, nameAr: "رأس السنة الميلادية", nameEn: "New Year's Day", date: "2026-01-01", type: "fixed", isRecurring: true },
  { id: 2, nameAr: "عيد العمال", nameEn: "Labor Day", date: "2026-05-01", type: "fixed", isRecurring: true },
  { id: 3, nameAr: "يوم الاستقلال", nameEn: "Independence Day", date: "2026-05-25", type: "fixed", isRecurring: true },
  { id: 4, nameAr: "عيد الجيش", nameEn: "Army Day", date: "2026-06-10", type: "fixed", isRecurring: true },
  { id: 5, nameAr: "عيد الفطر", nameEn: "Eid Al-Fitr", date: "2026-03-20", type: "islamic", isRecurring: false },
  { id: 6, nameAr: "عيد الأضحى", nameEn: "Eid Al-Adha", date: "2026-05-27", type: "islamic", isRecurring: false },
  { id: 7, nameAr: "المولد النبوي", nameEn: "Prophet's Birthday", date: "2026-09-15", type: "islamic", isRecurring: false },
  { id: 8, nameAr: "رأس السنة الهجرية", nameEn: "Islamic New Year", date: "2026-07-17", type: "islamic", isRecurring: false },
];

app.get("/api/public-holidays", auth, async (req, res) => {
  const { type, year } = req.query as Record<string, string>;
  let result = JORDAN_HOLIDAYS;
  if (type) result = result.filter(h => h.type === type);
  if (year) result = result.filter(h => h.date.startsWith(year));
  res.json({ success: true, data: result, total: result.length });
});

app.post("/api/public-holidays", auth, async (req, res) => {
  const h = { id: JORDAN_HOLIDAYS.length + 1, ...req.body };
  JORDAN_HOLIDAYS.push(h);
  res.status(201).json({ success: true, data: h });
});

app.get("/api/public-holidays/upcoming", auth, async (req, res) => {
  const { days = "90" } = req.query as Record<string, string>;
  const future = new Date();
  future.setDate(future.getDate() + parseInt(days));
  const now = new Date();
  const result = JORDAN_HOLIDAYS.filter(h => {
    const d = new Date(h.date);
    return d >= now && d <= future;
  });
  res.json({ success: true, data: result });
});

app.get("/api/public-holidays/reports", auth, async (req, res) => {
  const { type = "annual", year = String(new Date().getFullYear()) } = req.query as Record<string, string>;
  const holidays = JORDAN_HOLIDAYS.filter(h => h.date.startsWith(year)).map(h => ({ ...h, days: 1 }));
  if (type === "by-type") {
    const grouped = new Map<string, any>();
    for (const holiday of holidays) {
      const row = grouped.get(holiday.type) || { type: holiday.type, count: 0, days: 0, holidays: [] };
      row.count += 1;
      row.days += 1;
      row.holidays.push(holiday);
      grouped.set(holiday.type, row);
    }
    res.json({ success: true, data: Array.from(grouped.values()) }); return;
  }
  if (type === "monthly") {
    const months = Array.from({ length: 12 }, (_, index) => ({ month: index + 1, count: 0, days: 0, holidays: [] as any[] }));
    for (const holiday of holidays) {
      const month = Number(holiday.date.slice(5, 7));
      months[month - 1]!.count += 1;
      months[month - 1]!.days += 1;
      months[month - 1]!.holidays.push(holiday);
    }
    res.json({ success: true, data: months }); return;
  }
  if (type === "work-report") {
    res.json({
      success: true,
      data: holidays.map(h => ({
        id: h.id,
        nameAr: h.nameAr,
        nameEn: h.nameEn,
        date: h.date,
        type: h.type,
        dayOfWeek: new Date(h.date).toLocaleDateString("en-US", { weekday: "long" }),
        workImpact: "paid_holiday",
        affectedEmployees: "all",
      })),
    });
    return;
  }
  res.json({
    success: true,
    data: {
      year,
      total: holidays.length,
      totalDays: holidays.reduce((sum, h) => sum + h.days, 0),
      recurring: holidays.filter(h => h.isRecurring).length,
      national: holidays.filter(h => h.type === "fixed").length,
      religious: holidays.filter(h => h.type === "islamic").length,
      upcoming: holidays.filter(h => new Date(h.date) >= new Date()).slice(0, 5),
      list: holidays,
      byType: {
        fixed: holidays.filter(h => h.type === "fixed").length,
        islamic: holidays.filter(h => h.type === "islamic").length,
      },
    },
  });
});

