app.get("/api/workflows/:id/history", auth, async (req, res) => {
  try {
    const user = (req as AuthReq).user;
    const id = parseIntParam(req.params.id);
    const [action] = await db.select().from(employeeActionsTable)
      .where(and(eq(employeeActionsTable.id, id), eq(employeeActionsTable.companyId, user.companyId))).limit(1);
    if (!action) { res.status(404).json({ success: false, message: "Workflow not found" }); return; }
    if (user.role === "employee" && action.employeeId !== user.employeeId) {
      res.status(403).json({ success: false, message: "Forbidden" }); return;
    }
    if (user.role === "manager") {
      const scope = await getEmployeeScopeConditions(req as AuthReq);
      const team = await db.select({ id: employeesTable.id }).from(employeesTable).where(and(...scope, eq(employeesTable.isDeleted, false)));
      if (!team.some(e => e.id === action.employeeId)) { res.status(403).json({ success: false, message: "Forbidden" }); return; }
    }
    let parsed: any = { chain: getApprovalChain(action.actionType), steps: [] };
    if (action.approvalStepsJson) {
      try { parsed = JSON.parse(action.approvalStepsJson); } catch {}
    }
    const { rows } = await pool.query(`SELECT * FROM workflow_actions WHERE workflow_request_id = $1 ORDER BY created_at DESC`, [id]);
    res.json({ success: true, data: { workflow: action, approval: parsed, actions: rows } });
  } catch (e) {
    console.error("[GET /api/workflows/:id/history]", e);
    res.status(500).json({ success: false, message: "Internal server error" });
  }
});

async function notificationCenterList(user: AuthReq["user"], query: Record<string, any>) {
  const page = Math.max(Number(query.page || 1), 1);
  const limit = query.limit ? Number(query.limit) : Number(query.pageSize || 20);
  const pageSize = Math.min(Math.max(limit || 20, 1), 100);
  const where = ["recipient_user_id=$1", "is_deleted=false"];
  const params: any[] = [user.userId];
  if (query.status) { params.push(String(query.status)); where.push(`status=$${params.length}`); }
  if (query.type || query.notificationType) { params.push(String(query.type || query.notificationType)); where.push(`notification_type=$${params.length}`); }
  if (query.entityType) { params.push(String(query.entityType)); where.push(`entity_type=$${params.length}`); }
  const whereSql = where.join(" AND ");
  const totalRes = await pool.query(`SELECT COUNT(*)::int AS total FROM notifications WHERE ${whereSql}`, params);
  const unreadRes = await pool.query(`SELECT COUNT(*)::int AS count FROM notifications WHERE recipient_user_id=$1 AND status='unread' AND is_deleted=false`, [user.userId]);
  const rowParams = [...params, pageSize, (page - 1) * pageSize];
  const { rows } = await pool.query(
    `SELECT * FROM notifications WHERE ${whereSql} ORDER BY created_at DESC LIMIT $${rowParams.length - 1} OFFSET $${rowParams.length}`,
    rowParams,
  );
  const total = Number(totalRes.rows[0]?.total || 0);
  const normalizeNotification = (row: any) => {
    const item = camelAts(row);
    if (item.notificationType === "attendance_correction_hr_approved") {
      item.titleAr = "تم اعتماد طلب تصحيح الحضور";
      item.messageAr = `تم اعتماد طلب تصحيح حضورك #${item.entityId} من قبل الموارد البشرية.`;
      item.title = item.titleAr;
      item.message = item.messageAr;
    }
    if (item.notificationType === "leave_request_approved") {
      item.titleAr = "تمت الموافقة على طلب الإجازة";
      item.messageAr = "تمت الموافقة على طلب إجازتك.";
      item.title = item.titleAr;
      item.message = item.messageAr;
    }
    return item;
  };
  return { items: rows.map(normalizeNotification), total, page, pageSize, totalPages: Math.ceil(total / pageSize), unreadCount: Number(unreadRes.rows[0]?.count || 0) };
}

async function setNotificationStatus(user: AuthReq["user"], id: number, status: "read" | "unread") {
  const { rowCount } = await pool.query(
    `UPDATE notifications
        SET status=$1::varchar, read_at=CASE WHEN $1::varchar='read' THEN NOW() ELSE NULL END
      WHERE id=$2 AND recipient_user_id=$3 AND is_deleted=false`,
    [status, id, user.userId],
  );
  return rowCount ?? 0;
}

async function archiveNotification(user: AuthReq["user"], id: number) {
  const { rowCount } = await pool.query(
    `UPDATE notifications SET is_deleted=true WHERE id=$1 AND recipient_user_id=$2`,
    [id, user.userId],
  );
  return rowCount ?? 0;
}

