type MasterDataField = {
  key: string;
  column: string;
  required?: boolean;
  type?: "string" | "number" | "boolean" | "json";
};

type MasterDataConfig = {
  route: string;
  table: string;
  labelAr: string;
  labelEn: string;
  defaultSort: string;
  fields: MasterDataField[];
  searchColumns: string[];
  extraSelect?: string;
  joins?: string;
  filters?: Record<string, string>;
};

