// Bundle D: production export hardening
type BundleDExportDataset = "employees" | "attendance" | "payroll" | "recruitment" | "evaluations" | "reports" | "workflows";
type ExportFormat = "csv" | "xlsx" | "pdf";
type ExportJobStatus = "queued" | "running" | "completed" | "failed";
type ExportJob = {
  id: string;
  key: string;
  companyId: number;
  userId: number;
  role: string;
  dataset: BundleDExportDataset;
  format: ExportFormat;
  status: ExportJobStatus;
  attempts: number;
  createdAt: string;
  updatedAt: string;
  startedAt?: string;
  completedAt?: string;
  failedAt?: string;
  durationMs?: number;
  error?: string;
  fileName?: string;
  contentType?: string;
  size?: number;
  buffer?: Buffer;
  requestId?: string;
};
const exportJobs = new Map<string, ExportJob>();
const activeExportKeys = new Map<string, string>();
const EXPORT_JOB_RETENTION_MS = 30 * 60 * 1000;

function bundleDCanExport(user: any, dataset: BundleDExportDataset) {
  if (user?.role === "hradmin") return true;
  if (dataset === "payroll") return user?.role === "payrolladmin";
  if (dataset === "recruitment") return user?.role === "recruiter";
  if (dataset === "attendance") return ["manager", "employee"].includes(user?.role);
  if (dataset === "evaluations") return ["manager", "employee", "payrolladmin"].includes(user?.role);
  if (dataset === "employees") return user?.role === "manager";
  if (dataset === "reports") return ["payrolladmin", "manager"].includes(user?.role);
  if (dataset === "workflows") return ["manager", "payrolladmin"].includes(user?.role);
  return false;
}

function allowedExportDataset(dataset: string): dataset is BundleDExportDataset {
  return ["employees", "attendance", "payroll", "recruitment", "evaluations", "reports", "workflows"].includes(dataset);
}

function allowedExportFormat(format: string): format is ExportFormat {
  return ["csv", "xlsx", "pdf"].includes(format);
}

function csvEscape(value: unknown) {
  const text = value === null || value === undefined ? "" : String(value);
  return /[",\n\r]/.test(text) ? `"${text.replace(/"/g, '""')}"` : text;
}

function toCsv(columns: ExportColumn[], data: Record<string, unknown>[]) {
  const header = columns.map(c => csvEscape(c.headerAr ? `${c.header} / ${c.headerAr}` : c.header)).join(",");
  const rows = data.map(row => columns.map(c => csvEscape(row[c.key])).join(","));
  return "\uFEFF" + [header, ...rows].join("\r\n");
}

function pdfEscape(value: unknown) {
  return String(value ?? "").replace(/\\/g, "\\\\").replace(/\(/g, "\\(").replace(/\)/g, "\\)").replace(/[^\x20-\x7E]/g, "?");
}

function simplePdfBuffer(title: string, columns: ExportColumn[], data: Record<string, unknown>[]) {
  const lines = [title, `Generated: ${new Date().toISOString()}`, "", columns.map(c => c.header).join(" | ")];
  for (const row of data.slice(0, 80)) {
    lines.push(columns.map(c => String(row[c.key] ?? "").slice(0, 24)).join(" | "));
  }
  const content = [
    "BT",
    "/F1 10 Tf",
    "50 790 Td",
    ...lines.flatMap((line, index) => index === 0 ? [`(${pdfEscape(line)}) Tj`] : ["0 -14 Td", `(${pdfEscape(line)}) Tj`]),
    "ET",
  ].join("\n");
  const objects = [
    "1 0 obj << /Type /Catalog /Pages 2 0 R >> endobj",
    "2 0 obj << /Type /Pages /Kids [3 0 R] /Count 1 >> endobj",
    "3 0 obj << /Type /Page /Parent 2 0 R /MediaBox [0 0 842 595] /Resources << /Font << /F1 4 0 R >> >> /Contents 5 0 R >> endobj",
    "4 0 obj << /Type /Font /Subtype /Type1 /BaseFont /Helvetica >> endobj",
    `5 0 obj << /Length ${Buffer.byteLength(content, "utf8")} >> stream\n${content}\nendstream endobj`,
  ];
  let pdf = "%PDF-1.4\n";
  const offsets = [0];
  for (const object of objects) {
    offsets.push(Buffer.byteLength(pdf, "utf8"));
    pdf += object + "\n";
  }
  const xref = Buffer.byteLength(pdf, "utf8");
  pdf += `xref\n0 ${objects.length + 1}\n0000000000 65535 f \n`;
  for (let i = 1; i < offsets.length; i++) pdf += `${String(offsets[i]).padStart(10, "0")} 00000 n \n`;
  pdf += `trailer << /Size ${objects.length + 1} /Root 1 0 R >>\nstartxref\n${xref}\n%%EOF`;
  return Buffer.from(pdf, "utf8");
}

async function bundleDExportData(user: any, dataset: BundleDExportDataset) {
  if (dataset === "employees") {
    const params: any[] = [user.companyId];
    let scope = "";
    if (user.role === "manager") scope = ` AND e.direct_manager_id=$${params.push(user.employeeId ?? -1)}`;
    const { rows } = await pool.query(
      `SELECT e.employee_code AS "employeeCode", CONCAT_WS(' ', e.first_name_en, e.middle_name_en, e.last_name_en) AS "nameEn",
              CONCAT_WS(' ', e.first_name_ar, e.middle_name_ar, e.last_name_ar) AS "nameAr", d.name_en AS department, e.employment_status AS status
       FROM employees e LEFT JOIN departments d ON d.id=e.department_id AND d.company_id=e.company_id
       WHERE e.company_id=$1 AND e.is_deleted=false${scope} ORDER BY e.employee_code LIMIT 500`,
      params,
    );
    return { title: "Employee Export", titleAr: "تصدير الموظفين", rows, columns: [
      { key: "employeeCode", header: "Code", headerAr: "الكود", width: 16 },
      { key: "nameEn", header: "English Name", headerAr: "الاسم الإنجليزي", width: 24 },
      { key: "nameAr", header: "Arabic Name", headerAr: "الاسم العربي", width: 24, isArabic: true },
      { key: "department", header: "Department", headerAr: "القسم", width: 20 },
      { key: "status", header: "Status", headerAr: "الحالة", width: 16 },
    ] as ExportColumn[] };
  }

  if (dataset === "attendance") {
    const params: any[] = [user.companyId];
    let scope = "";
    if (user.role === "employee") scope = ` AND ar.employee_id=$${params.push(user.employeeId ?? -1)}`;
    if (user.role === "manager") scope = ` AND ar.employee_id IN (SELECT id FROM employees WHERE company_id=$1 AND direct_manager_id=$${params.push(user.employeeId ?? -1)} AND is_deleted=false)`;
    const { rows } = await pool.query(
      `SELECT ar.date AS date, e.employee_code AS "employeeCode", CONCAT_WS(' ', e.first_name_en, e.last_name_en) AS employee,
              ar.status, ar.clock_in AS "checkIn", ar.clock_out AS "checkOut"
       FROM attendance_records ar JOIN employees e ON e.id=ar.employee_id
       WHERE e.company_id=$1${scope} ORDER BY ar.date DESC LIMIT 500`,
      params,
    );
    return { title: "Attendance Export", titleAr: "تصدير الحضور", rows, columns: [
      { key: "date", header: "Date", headerAr: "التاريخ", isDate: true },
      { key: "employeeCode", header: "Code", headerAr: "الكود" },
      { key: "employee", header: "Employee", headerAr: "الموظف" },
      { key: "status", header: "Status", headerAr: "الحالة" },
      { key: "checkIn", header: "Check In", headerAr: "الدخول" },
      { key: "checkOut", header: "Check Out", headerAr: "الخروج" },
    ] as ExportColumn[] };
  }

  if (dataset === "payroll") {
    const { rows } = await pool.query(
      `SELECT pr.run_month AS month, pr.run_year AS year, pr.status, e.employee_code AS "employeeCode",
              ps.gross_salary AS gross, ps.total_deductions AS deductions, ps.net_salary AS net
       FROM payslips ps JOIN payroll_runs pr ON pr.id=ps.payroll_run_id
       JOIN employees e ON e.id=ps.employee_id AND e.company_id=pr.company_id
       WHERE pr.company_id=$1 ORDER BY pr.run_year DESC, pr.run_month DESC, e.employee_code LIMIT 500`,
      [user.companyId],
    );
    return { title: "Payroll Export", titleAr: "تصدير الرواتب", rows, columns: [
      { key: "month", header: "Month", headerAr: "الشهر", isNumeric: true },
      { key: "year", header: "Year", headerAr: "السنة", isNumeric: true },
      { key: "employeeCode", header: "Employee", headerAr: "الموظف" },
      { key: "gross", header: "Gross", headerAr: "الإجمالي", isCurrency: true },
      { key: "deductions", header: "Deductions", headerAr: "الاقتطاعات", isCurrency: true },
      { key: "net", header: "Net", headerAr: "الصافي", isCurrency: true },
      { key: "status", header: "Status", headerAr: "الحالة" },
    ] as ExportColumn[] };
  }

  if (dataset === "recruitment") {
    const { rows } = await pool.query(
      `SELECT c.candidate_number AS code, c.full_name_en AS "nameEn", c.full_name_ar AS "nameAr", c.email, c.phone, c.status,
              COALESCE(s.name_en, c.status) AS stage, c.rating
       FROM candidates c
       LEFT JOIN recruitment_pipeline_stages s ON s.id=c.current_stage_id AND s.company_id=c.company_id
       WHERE c.company_id=$1 AND c.is_deleted=false ORDER BY c.created_at DESC LIMIT 500`,
      [user.companyId],
    );
    return { title: "Recruitment Pipeline Export", titleAr: "تصدير مسار التوظيف", rows, columns: [
      { key: "code", header: "Code", headerAr: "الكود" },
      { key: "nameEn", header: "English Name", headerAr: "الاسم الإنجليزي" },
      { key: "nameAr", header: "Arabic Name", headerAr: "الاسم العربي", isArabic: true },
      { key: "email", header: "Email", headerAr: "البريد" },
      { key: "status", header: "Status", headerAr: "الحالة" },
      { key: "stage", header: "Stage", headerAr: "المرحلة" },
      { key: "rating", header: "Rating", headerAr: "التقييم", isNumeric: true },
    ] as ExportColumn[] };
  }

  if (dataset === "evaluations") {
    const params: any[] = [user.companyId];
    let scope = "";
    if (user.role === "employee") scope = ` AND pe.employee_id=$${params.push(user.employeeId ?? -1)}`;
    if (user.role === "manager") scope = ` AND pe.employee_id IN (SELECT id FROM employees WHERE company_id=$1 AND direct_manager_id=$${params.push(user.employeeId ?? -1)} AND is_deleted=false)`;
    const { rows } = await pool.query(
      `SELECT e.employee_code AS "employeeCode", CONCAT_WS(' ', e.first_name_en, e.last_name_en) AS employee,
              pe.status, pe.final_score AS "finalScore", pe.final_rating_code AS rating, pe.recommendation
       FROM performance_evaluations pe JOIN employees e ON e.id=pe.employee_id AND e.company_id=pe.company_id
       WHERE pe.company_id=$1 AND pe.is_deleted=false${scope} ORDER BY pe.created_at DESC LIMIT 500`,
      params,
    );
    return { title: "Performance Evaluation Export", titleAr: "تصدير تقييم الأداء", rows, columns: [
      { key: "employeeCode", header: "Code", headerAr: "الكود" },
      { key: "employee", header: "Employee", headerAr: "الموظف" },
      { key: "status", header: "Status", headerAr: "الحالة" },
      { key: "finalScore", header: "Final Score", headerAr: "النتيجة", isNumeric: true },
      { key: "rating", header: "Rating", headerAr: "التقدير" },
      { key: "recommendation", header: "Recommendation", headerAr: "التوصية" },
    ] as ExportColumn[] };
  }

  if (dataset === "workflows") {
    const { rows } = await pool.query(
      `SELECT entity_type AS "entityType", entity_id AS "entityId", status, current_approver_role AS "approverRole", created_at AS "createdAt"
       FROM performance_workflow_instances WHERE company_id=$1 AND is_deleted=false ORDER BY created_at DESC LIMIT 500`,
      [user.companyId],
    );
    return { title: "Workflow Export", titleAr: "تصدير سير العمل", rows, columns: [
      { key: "entityType", header: "Entity", headerAr: "الكيان" },
      { key: "entityId", header: "ID", headerAr: "المعرف" },
      { key: "status", header: "Status", headerAr: "الحالة" },
      { key: "approverRole", header: "Approver Role", headerAr: "دور المعتمد" },
      { key: "createdAt", header: "Created", headerAr: "تاريخ الإنشاء", isDate: true },
    ] as ExportColumn[] };
  }

  const { rows } = await pool.query(
    `SELECT code, name_en AS "nameEn", name_ar AS "nameAr", report_type AS "reportType", module_scope AS "moduleScope", is_active AS "isActive"
     FROM enterprise_report_definitions WHERE company_id=$1 AND is_deleted=false ORDER BY module_scope, code LIMIT 500`,
    [user.companyId],
  );
  return { title: "Report Definitions Export", titleAr: "تصدير تعريفات التقارير", rows, columns: [
    { key: "code", header: "Code", headerAr: "الكود" },
    { key: "nameEn", header: "English Name", headerAr: "الاسم الإنجليزي" },
    { key: "nameAr", header: "Arabic Name", headerAr: "الاسم العربي", isArabic: true },
    { key: "reportType", header: "Type", headerAr: "النوع" },
    { key: "moduleScope", header: "Module", headerAr: "الوحدة" },
    { key: "isActive", header: "Active", headerAr: "نشط" },
  ] as ExportColumn[] };
}

async function buildProductionExport(user: any, dataset: BundleDExportDataset, format: ExportFormat) {
  const started = Date.now();
  const exportData = await bundleDExportData(user, dataset);
  const fileBase = `zenjo-${dataset}-${new Date().toISOString().slice(0, 10)}`;
  if (format === "csv") {
    const buffer = Buffer.from(toCsv(exportData.columns, exportData.rows), "utf8");
    return { buffer, contentType: "text/csv; charset=utf-8", fileName: `${fileBase}.csv`, rowCount: exportData.rows.length, durationMs: Date.now() - started };
  }
  if (format === "pdf") {
    const buffer = simplePdfBuffer(exportData.title, exportData.columns, exportData.rows);
    return { buffer, contentType: "application/pdf", fileName: `${fileBase}.pdf`, rowCount: exportData.rows.length, durationMs: Date.now() - started };
  }
  const company = await pool.query(`SELECT name_en, name_ar FROM companies WHERE id=$1`, [user.companyId]);
  const buffer = await generateExcelBuffer({
    sheetName: dataset,
    columns: exportData.columns,
    data: exportData.rows,
    companyName: company.rows[0]?.name_en || "ZenJO",
    companyNameAr: company.rows[0]?.name_ar || undefined,
    reportTitle: exportData.title,
    reportTitleAr: exportData.titleAr,
  });
  return { buffer, contentType: "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet", fileName: `${fileBase}.xlsx`, rowCount: exportData.rows.length, durationMs: Date.now() - started };
}

function exportQueueStats() {
  const byStatus: Record<string, number> = {};
  for (const job of exportJobs.values()) byStatus[job.status] = (byStatus[job.status] || 0) + 1;
  return { mode: runtimeStore.mode, size: exportJobs.size, activeKeys: activeExportKeys.size, byStatus };
}

function sanitizeJob(job: ExportJob) {
  const { buffer: _buffer, ...safe } = job;
  return safe;
}

function serializeJob(job: ExportJob) {
  return { ...sanitizeJob(job), bufferBase64: job.buffer ? job.buffer.toString("base64") : undefined };
}

function hydrateJob(value: any): ExportJob | null {
  if (!value?.id) return null;
  const { bufferBase64, ...job } = value;
  return { ...job, buffer: bufferBase64 ? Buffer.from(bufferBase64, "base64") : undefined } as ExportJob;
}

async function persistExportJob(job: ExportJob) {
  await runtimeStore.setJson(`export-job:${job.id}`, serializeJob(job), Math.ceil(EXPORT_JOB_RETENTION_MS / 1000));
  if (["queued", "running"].includes(job.status)) await runtimeStore.setJson(`export-active:${job.key}`, job.id, Math.ceil(EXPORT_JOB_RETENTION_MS / 1000));
  else await runtimeStore.delete(`export-active:${job.key}`);
}

async function loadExportJob(id: string) {
  const local = exportJobs.get(id);
  if (local) return local;
  const persisted = hydrateJob(await runtimeStore.getJson(`export-job:${id}`));
  if (persisted) exportJobs.set(persisted.id, persisted);
  return persisted;
}

async function loadActiveExportJob(key: string) {
  const localId = activeExportKeys.get(key);
  const local = localId ? await loadExportJob(localId) : null;
  if (local) return local;
  const persistedId = await runtimeStore.getJson<string>(`export-active:${key}`);
  const persisted = persistedId ? await loadExportJob(persistedId) : null;
  if (persisted) activeExportKeys.set(key, persisted.id);
  return persisted;
}

async function runExportJob(id: string) {
  const job = await loadExportJob(id);
  if (!job || job.status === "running" || job.status === "completed") return;
  job.status = "running";
  job.attempts += 1;
  job.startedAt = new Date().toISOString();
  job.updatedAt = job.startedAt;
  await persistExportJob(job);
  const started = Date.now();
  try {
    const built = await buildProductionExport({
      userId: job.userId,
      companyId: job.companyId,
      role: job.role,
      employeeId: null,
    }, job.dataset, job.format);
    job.buffer = built.buffer;
    job.contentType = built.contentType;
    job.fileName = built.fileName;
    job.size = built.buffer.length;
    job.status = "completed";
    job.completedAt = new Date().toISOString();
    job.durationMs = Date.now() - started;
    job.updatedAt = job.completedAt;
    await persistExportJob(job);
    safeLog({ level: "info", event: "export_job_completed", requestId: job.requestId, jobId: job.id, dataset: job.dataset, format: job.format, userId: job.userId, companyId: job.companyId, durationMs: job.durationMs, size: job.size });
  } catch (e: any) {
    job.status = "failed";
    job.failedAt = new Date().toISOString();
    job.updatedAt = job.failedAt;
    job.durationMs = Date.now() - started;
    job.error = IS_PRODUCTION ? "Export generation failed" : (e?.stack || e?.message || String(e));
    await persistExportJob(job);
    safeLog({ level: "error", event: "export_job_failed", requestId: job.requestId, jobId: job.id, dataset: job.dataset, format: job.format, userId: job.userId, companyId: job.companyId, durationMs: job.durationMs, error: job.error });
  } finally {
    activeExportKeys.delete(job.key);
    await runtimeStore.delete(`export-active:${job.key}`);
    setTimeout(() => exportJobs.delete(id), EXPORT_JOB_RETENTION_MS).unref?.();
  }
}

app.get("/api/production/exports/:dataset", auth, async (req, res) => {
  try {
    const user = (req as AuthReq).user;
    const requestId = (req as any).requestId;
    const started = Date.now();
    const dataset = String(req.params["dataset"] || "");
    const format = String(req.query["format"] || "xlsx").toLowerCase();
    if (!allowedExportDataset(dataset)) return res.status(404).json({ success: false, message: "Export dataset not found" });
    if (!allowedExportFormat(format)) return res.status(400).json({ success: false, message: "format must be csv, xlsx, or pdf" });
    if (!bundleDCanExport(user, dataset)) return res.status(403).json({ success: false, message: "Forbidden" });

    const built = await buildProductionExport(user, dataset, format);
    safeLog({ level: "info", event: "export_sync_completed", requestId, dataset, format, userId: user.userId, companyId: user.companyId, durationMs: Date.now() - started, size: built.buffer.length });
    res.setHeader("Content-Type", built.contentType);
    res.setHeader("Content-Disposition", `attachment; filename="${built.fileName}"`);
    res.setHeader("x-export-duration-ms", String(built.durationMs));
    res.setHeader("x-export-row-count", String(built.rowCount));
    res.send(built.buffer);
  } catch (e: any) {
    console.error("[GET /api/production/exports/:dataset]", e);
    res.status(bundleCStatus(e)).json({ success: false, message: bundleCMessage(e), requestId: (req as any).requestId });
  }
});

app.post("/api/production/exports/:dataset/jobs", auth, async (req, res) => {
  try {
    const user = (req as AuthReq).user;
    const dataset = String(req.params["dataset"] || "");
    const format = String(req.body?.format || req.query["format"] || "xlsx").toLowerCase();
    if (!allowedExportDataset(dataset)) return res.status(404).json({ success: false, message: "Export dataset not found" });
    if (!allowedExportFormat(format)) return res.status(400).json({ success: false, message: "format must be csv, xlsx, or pdf" });
    if (!bundleDCanExport(user, dataset)) return res.status(403).json({ success: false, message: "Forbidden" });
    const key = `${user.companyId}:${user.userId}:${dataset}:${format}`;
    const existing = await loadActiveExportJob(key);
    if (existing && ["queued", "running"].includes(existing.status)) {
      res.status(202).json({ success: true, data: sanitizeJob(existing), deduped: true });
      return;
    }
    const now = new Date().toISOString();
    const job: ExportJob = {
      id: crypto.randomUUID(),
      key,
      companyId: user.companyId,
      userId: user.userId,
      role: user.role,
      dataset,
      format,
      status: "queued",
      attempts: 0,
      createdAt: now,
      updatedAt: now,
      requestId: (req as any).requestId,
    };
    exportJobs.set(job.id, job);
    activeExportKeys.set(key, job.id);
    await persistExportJob(job);
    safeLog({ level: "info", event: "export_job_queued", requestId: job.requestId, jobId: job.id, dataset, format, userId: user.userId, companyId: user.companyId });
    setImmediate(() => runExportJob(job.id));
    res.status(202).json({ success: true, data: sanitizeJob(job) });
  } catch (e: any) {
    console.error("[POST /api/production/exports/:dataset/jobs]", e);
    res.status(500).json({ success: false, message: IS_PRODUCTION ? "Export queue failed" : e?.message, requestId: (req as any).requestId });
  }
});

app.get("/api/production/exports/jobs/:id", auth, async (req, res) => {
  const user = (req as AuthReq).user;
  const job = await loadExportJob(String(req.params["id"] || ""));
  if (!job || job.companyId !== user.companyId || job.userId !== user.userId) return res.status(404).json({ success: false, message: "Export job not found" });
  res.json({ success: true, data: sanitizeJob(job) });
});

app.post("/api/production/exports/jobs/:id/retry", auth, async (req, res) => {
  const user = (req as AuthReq).user;
  const job = await loadExportJob(String(req.params["id"] || ""));
  if (!job || job.companyId !== user.companyId || job.userId !== user.userId) return res.status(404).json({ success: false, message: "Export job not found" });
  if (job.status !== "failed") return res.status(409).json({ success: false, message: "Only failed jobs can be retried" });
  job.status = "queued";
  job.error = undefined;
  job.updatedAt = new Date().toISOString();
  activeExportKeys.set(job.key, job.id);
  await persistExportJob(job);
  setImmediate(() => runExportJob(job.id));
  res.status(202).json({ success: true, data: sanitizeJob(job) });
});

app.get("/api/production/exports/jobs/:id/download", auth, async (req, res) => {
  const user = (req as AuthReq).user;
  const job = await loadExportJob(String(req.params["id"] || ""));
  if (!job || job.companyId !== user.companyId || job.userId !== user.userId) return res.status(404).json({ success: false, message: "Export job not found" });
  if (job.status !== "completed" || !job.buffer || !job.contentType || !job.fileName) return res.status(409).json({ success: false, message: "Export job is not ready" });
  res.setHeader("Content-Type", job.contentType);
  res.setHeader("Content-Disposition", `attachment; filename="${job.fileName}"`);
  res.setHeader("x-export-job-id", job.id);
  res.send(job.buffer);
});

app.get("/api/ops/metrics", auth, async (req, res) => {
  const user = (req as AuthReq).user;
  if (!["hradmin", "payrolladmin", "superadmin"].includes(user.role)) return res.status(403).json({ success: false, message: "Forbidden" });
  const metrics = await runtimeStore.metrics();
  const routes = Object.entries(metrics).map(([key, m]) => ({
    route: key,
    count: m.count,
    errors: m.errors,
    avgMs: m.count ? Math.round(m.totalMs / m.count) : 0,
    maxMs: m.maxMs,
  })).sort((a, b) => b.count - a.count).slice(0, 200);
  res.json({ success: true, data: { generatedAt: new Date().toISOString(), version: SERVICE_VERSION, queue: exportQueueStats(), routes } });
});

registerComplianceContractsRoutes(app, auth);

app.use((err: any, req: express.Request, res: express.Response, _next: express.NextFunction) => {
  const requestId = (req as any).requestId || crypto.randomUUID();
  safeLog({
    level: "error",
    event: "unhandled_request_error",
    requestId,
    route: req.path,
    method: req.method,
    status: err?.status || 500,
    error: IS_PRODUCTION ? err?.message || "Unhandled error" : err?.stack || err?.message || String(err),
  });
  if (res.headersSent) return;
  res.status(err?.status || 500).json({
    success: false,
    message: IS_PRODUCTION ? "Internal server error" : (err?.message || "Internal server error"),
    requestId,
  });
});

process.on("unhandledRejection", (reason) => {
  safeLog({ level: "error", event: "unhandled_rejection", error: IS_PRODUCTION ? "Unhandled promise rejection" : String(reason) });
});

process.on("uncaughtException", (error) => {
  safeLog({ level: "error", event: "uncaught_exception", error: IS_PRODUCTION ? error.message : error.stack || error.message });
});

app.listen(PORT, "0.0.0.0", () => {
  console.log(`ZenJO API server running on http://localhost:${PORT}`);
});

export default app;
